const r="http://localhost:5000";async function s(t){try{const e={method:t.method,headers:{"Content-Type":"application/json"}};t.body&&(e.body=JSON.stringify(t.body));const o=await fetch(`${r}${t.path}`,e),n=await o.text();let a;try{a=JSON.parse(n)}catch{a=n}return{status:o.status,ok:o.ok,body:a}}catch(e){return{status:0,ok:!1,body:String(e)}}}chrome.runtime.onMessage.addListener(t=>{if(t&&typeof t=="object"&&t.type==="API_REQUEST")return s(t)});
